                "responses": {"200": {"description": "Order status"}}
            }
        },
        "/orders/{orderId}/return": {
            "post": {
                "operationId": "initiateReturn",
                "summary": "Initiate a return",
                "requestBody": {
                    "content": {"application/json": {"schema": {
                        "type": "object",
                        "properties": {
                            "orderId": {"type": "string"},
                            "reason": {"type": "string"},
                        },
                        "required": ["orderId", "reason"]
                    }}}
                },
                "responses": {"200": {"description": "Return initiated"}}
            }
        }
    }
})

