import json

def lambda_handler(event, context):
    """
    Bedrock Agents calls this Lambda with the action group and
    the parameters the model extracted from the conversation.
    """
    action_group = event["actionGroup"]
    api_path     = event["apiPath"]
    http_method  = event["httpMethod"]
    parameters   = event.get("parameters", [])
    request_body = event.get("requestBody", {})

    # Route by operation
    if api_path == "/orders/{orderId}" and http_method == "GET":
        order_id = next(p["value"] for p in parameters if p["name"] == "orderId")
        result   = get_order_from_db(order_id)

    elif api_path == "/orders/{orderId}/return" and http_method == "POST":
        body      = json.loads(request_body["content"]["application/json"]["body"])
        order_id  = body["orderId"]
        reason    = body["reason"]
        result    = initiate_return(order_id, reason)

    else:
        result = {"error": "Unknown operation"}

    # Bedrock Agents expects this exact response shape
    return {
        "messageVersion": "1.0",
        "response": {
            "actionGroup": action_group,
            "apiPath": api_path,
            "httpMethod": http_method,
            "httpStatusCode": 200,
            "responseBody": {"application/json": {"body": json.dumps(result)}},
        }
    }

def get_order_from_db(order_id: str) -> dict:
    # Real implementation queries your database
    return {"orderId": order_id, "status": "shipped", "eta": "2024-03-15"}

def initiate_return(order_id: str, reason: str) -> dict:
    return {"returnId": f"RET-{order_id}", "status": "initiated", "reason": reason}

